SELECT ForecastBudget.No_, ForecastBudget.Description, ForecastBudget.BudgetType, ForecastBudget.[Average Unit Price], ForecastBudget.[Posting Date], ForecastBudget.[Trademark Code], ForecastBudget.[Sales Season Code], ForecastBudget.[Salesperson Code], ForecastBudget.SalesPersonName, ForecastBudget.[Geographical Zone], ForecastBudget.CustomerCode, ForecastBudget.CustomerName, ForecastBudget.CustomerGeorgraficalZone, ForecastBudget.CustomerGeorgraficalZoneDescription, ForecastBudget.CustomerGeorgraficalZone2, ForecastBudget.CustomerGeorgraficalZone2Description, ForecastBudget.City, ForecastBudget.[Current Risk], ForecastBudget.[Authorized Stores Number], IIf([budgettype]="MAIN",[linebudgetqty],[actualqty]) AS NewLineBudgetQty, IIf([budgettype]="MAIN",[linebudgetamount],[actualamount]) AS NewLineBudgetAmount, IIf([budgettype]="MAIN",[linebudgetqty],[actualqty]) AS NewLineRevisedBudgetQty, IIf([budgettype]="MAIN",[linebudgetamount],[actualamount]) AS NewLineRevisedBudgetAmount, IIf([budgettype]="MAIN",[linebudgetqty],[actualqty]) AS NewCurrentBudgetQty, IIf([budgettype]="MAIN",[linebudgetamount],[actualamount]) AS NewCurrentBudgetAmount, IIf([budgettype]="MAIN",[previouscorrseasonqty],0) AS NewPreviousCorrSeasonQty, IIf([budgettype]="MAIN",[previousCorrseasonamount],0) AS NewPreviousCorrSeasonAmount, ForecastBudget.ActualQty, ForecastBudget.ActualAmount, ForecastBudget.NoBuyReaon, IIf([budgettype]="MAIN",[forecastqty],[actualqty]) AS NewForecastQty, IIf([budgettype]="MAIN",[forecastamount],[actualamount]) AS NewForecastAmount, ForecastBudget.BudgetLineStatus, IIf([budgettype]="MAIN",[forecastqty],[actualqty]) AS NewAdjustedForecastQty, IIf([budgettype]="MAIN",[forecastamount],[actualamount]) AS NewAdjustedForecastAmount, ForecastBudget.[Appointment Date], ForecastBudget.Note
FROM ForecastBudget
WHERE (((ForecastBudget.[Trademark Code])="AP") AND ((ForecastBudget.[Sales Season Code])="E17"));

